package com.taskflow.entity;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.time.LocalDateTime;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("User Entity")
class UserTest {

    @Test
    @DisplayName("should create User with all required fields")
    void shouldCreateUserWithAllRequiredFields() {
        User user = new User();
        user.setUsername("testuser");
        user.setPassword("hashedpassword");
        user.setDisplayName("Test User");

        assertThat(user.getUsername()).isEqualTo("testuser");
        assertThat(user.getPassword()).isEqualTo("hashedpassword");
        assertThat(user.getDisplayName()).isEqualTo("Test User");
    }

    @Test
    @DisplayName("should have null id before persistence")
    void shouldHaveNullIdBeforePersistence() {
        User user = new User();
        assertThat(user.getId()).isNull();
    }

    @Test
    @DisplayName("should have createdAt field")
    void shouldHaveCreatedAtField() {
        User user = new User();
        user.setCreatedAt(LocalDateTime.now());
        assertThat(user.getCreatedAt()).isNotNull();
    }
}

