package com.taskflow.dto;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.assertj.core.api.Assertions.assertThat;

@DisplayName("Auth DTO Validation")
class AuthDtoValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setUpValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    // ========== RegisterRequest ==========

    @Nested
    @DisplayName("RegisterRequest")
    class RegisterRequestTests {

        // --- Red/Green: Happy Path ---

        @Test
        @DisplayName("should pass validation with valid input")
        void shouldPassValidationWithValidInput() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("validuser");
            request.setPassword("password123");
            request.setDisplayName("Valid User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isEmpty();
        }

        // --- Username Validation ---

        @Test
        @DisplayName("should fail validation when username is null")
        void shouldFailValidationWhenUsernameIsNull() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername(null);
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should fail validation when username is too short (2 chars)")
        void shouldFailValidationWhenUsernameIsTooShort() {
            RegisterRequest request = new RegisterRequest();
            request.setUsername("ab");
            request.setPassword("password123");
            request.setDisplayName("Test User");

            Set<ConstraintViolation<RegisterRequest>> violations = validator.validate(request);
            assertThat(violations).isNotEmpty();
            assertThat(violations).anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        }

        @Test
        @DisplayName("should pass validation when username is exactly 3 chars")
